var e=[{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`아르카데나 제국.`,JPN:`アルカデナ帝国。`,ENG:`The Empire of Arcadena.`,TWN:`艾爾卡特納帝國。`},stage:{bg:`CASTLE_01`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`다섯 연방국과 세 공국으로부터 충성 서약을 받은 인류 최강의 대제국.`,JPN:`5つの連邦国と3つの公国から忠誠誓約を受けた、人類最強の大帝国。`,ENG:`It was once the most powerful empire known to man, with five federations and three duchies swearing vassalage.`,TWN:`5個聯邦國家和3個公國都宣誓效忠最強帝國。`},stage:{bg:`CASTLE_01`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`그리고……. 이제는 모두 사라져 버린, 먼 옛날의 이야기.`,JPN:`そして……今やすべてが消えてしまった、遠い昔の話。`,ENG:`But now, the story of this empire lingers like a faraway echo...`,TWN:`然而……都些都已經是不復存在的過去式。`},stage:{bg:`CASTLE_01`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`이것이……. 등대.`,JPN:`これが……灯台。`,ENG:`So... this is the Lighthouse.`,TWN:`這是……燈塔。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`말씀하신 노바급 리액터와 늑대의 클리포트 인자 결정을 확보했습니다.`,JPN:`おっしゃられていたノヴァ級リアクターと
狼のクリフォト・ファクターの結晶を確保しました。`,ENG:`I brought the Nova-Class Reactor and the Wolf’s crystallized Qliphoth Factor, Your Highness.`,TWN:`您說的諾瓦反應爐和狼的逆卡巴拉因子結晶到手。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`훌륭하군. 마르티네즈 백작 영애.`,JPN:`見事な働きだ。マルチネス伯爵令嬢。`,ENG:`You did well, Lady Martinez.`,TWN:`真是出色，馬汀尼茲伯爵的千金。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}},sfx:`FX_CUTSCEN_BEEP`},{id:`L11_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`이대로만 간다면 네 가문이 지은 죄를 씻어내는 것도 금방이겠어.`,JPN:`このまま行けば、貴様の一族が犯した罪を償えるのもすぐだろう。`,ENG:`I have a feeling that you will clear your family's name soon enough.`,TWN:`照這樣下去，應該很快就可以洗淨你家族的罪孽。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`그, 그렇다면?`,JPN:`ま、誠でしょうか？`,ENG:`D-does that mean...`,TWN:`真…真的嗎？`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`하지만 반역이라는 죄값이 그리 가벼운 건 아니지.`,JPN:`だが反逆という罪の代償は軽いものではない。`,ENG:`But... your family betrayed the Empire, and that is not a sin that will wash away very easily.`,TWN:`但造反可是重罪。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`그러니 지금과 같이 조금 더 분발해 보도록.`,JPN:`これまで以上に奮起するがいい。`,ENG:`So keep up the good work.`,TWN:`所以你要再更努力一點！`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`그대를 처형하는 대신 구원기사단에 들인 내 결정이 틀리지 않았음을 납득할 수 있게 말이다.`,JPN:`貴様を処刑する代わりに救世騎士団に迎えた私の判断が
間違いではなかったことを証明してみせよ。`,ENG:`Don’t make me regret my decision that let you join the Knights of Redemption instead of executing you.`,TWN:`這樣才能證明，當初我沒有將你處死，而是將你放到救贖騎士團的這個決定是正確的。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`……알겠습니다.`,JPN:`……承知いたしました。`,ENG:`... Yes, Your Highness.`,TWN:`……是的。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`그러면 이제 새로운 시대의 막을 올릴 시간이로군.`,JPN:`もうじき新たな時代の幕が上がる。`,ENG:`So, it’s time to start the new era.`,TWN:`那接下來就是揭開新時代序幕的時刻囉。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`가지고 온 물건을 등대에 장착해라.`,JPN:`持ってきた物を灯台に接続しろ。`,ENG:`Install the items you brought to the Lighthouse.`,TWN:`把你帶回來的東西裝到燈塔上。`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};